import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.CQYuu_FX.js";const p=JSON.parse('{"title":"在庫・レシピ管理","description":"","frontmatter":{"title":"在庫・レシピ管理"},"headers":[],"relativePath":"tenant/11-inventory.md","filePath":"tenant/11-inventory.md"}'),l={name:"tenant/11-inventory.md"};function i(o,t,n,h,c,s){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_11-在庫・レシピ管理" tabindex="-1">11. 在庫・レシピ管理 <a class="header-anchor" href="#_11-在庫・レシピ管理" aria-label="Permalink to &quot;11. 在庫・レシピ管理&quot;">​</a></h1><p>在庫・レシピ管理では、原材料、在庫数、使用量、棚卸し、AI需要予測を管理します。品切れ防止、原価確認、仕込み量の判断、売り切れ管理に役立ちます。</p><p>POSLAの在庫は「商品単位」ではなく、商品に紐づく「原材料単位」で管理します。たとえば、唐揚げ定食に「鶏肉 180g」「米 200g」「タレ 30ml」を登録しておくと、会計完了時に注文数に応じて原材料在庫が減ります。</p><h2 id="画面構成" tabindex="-1">画面構成 <a class="header-anchor" href="#画面構成" aria-label="Permalink to &quot;画面構成&quot;">​</a></h2><p>管理画面の <strong>在庫・レシピ</strong> には、主に2つのサブタブがあります。</p><table tabindex="0"><thead><tr><th>サブタブ</th><th>できること</th><th>主な用途</th></tr></thead><tbody><tr><td>原材料一覧</td><td>原材料の追加、編集、削除、棚卸し、CSVインポート/エクスポート</td><td>在庫数、単位、原価、低在庫アラートの管理</td></tr><tr><td>レシピ設定</td><td>メニューごとに使用する原材料と数量を登録、CSVインポート/エクスポート</td><td>会計時の自動在庫減算、原価計算、品切れ連動の土台</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">最初にメニュー登録が必要です</p><p>レシピ設定は、登録済みのメニューに原材料を紐づけます。メニューがない場合、レシピ設定に対象商品が表示されません。先にカテゴリ、商品、店舗メニューの設定を済ませてください。</p></div><h2 id="在庫の自動更新" tabindex="-1">在庫の自動更新 <a class="header-anchor" href="#在庫の自動更新" aria-label="Permalink to &quot;在庫の自動更新&quot;">​</a></h2><p>POSLAでは、以下のタイミングで在庫が自動的に更新されます。</p><ul><li><strong>決済完了時</strong>: 会計が完了した時点で、実在庫が正式に減算されます。</li><li><strong>セルフ会計の確定時</strong>: お客様側で会計が確定した場合も、同じレシピ設定を使って在庫が減算されます。</li><li><strong>棚卸し保存時</strong>: 店舗で数えた実在庫を入力すると、原材料の現在庫が更新されます。</li></ul><div class="info custom-block"><p class="custom-block-title">会計を優先する設計です</p><p>一時的な通信不良が起きても、お客様のお会計を止めにくいようにしています。在庫反映にずれが出た場合は、営業後に棚卸しや履歴を確認して調整してください。</p></div><h3 id="在庫消費の正確性" tabindex="-1">在庫消費の正確性 <a class="header-anchor" href="#在庫消費の正確性" aria-label="Permalink to &quot;在庫消費の正確性&quot;">​</a></h3><p>通信エラーなどで同じ会計が再実行されても、在庫が二重に減らないようにしています。</p><ul><li>各会計に対して、在庫を一度だけ反映する仕組みがあります。</li><li>どの注文で、いつ、どの原材料が使われたかの履歴を残しているため、後から確認できます。</li><li>レシピや原材料が未設定の商品は、自動減算の対象になりません。</li><li>会計済み注文の取消や返金を行った場合は、在庫を自動で戻す前提にせず、店舗の棚卸し・調整で整えてください。</li></ul><h2 id="原材料を登録する" tabindex="-1">原材料を登録する <a class="header-anchor" href="#原材料を登録する" aria-label="Permalink to &quot;原材料を登録する&quot;">​</a></h2><ol><li>管理画面で <strong>在庫・レシピ</strong> を開きます。</li><li><strong>原材料一覧</strong> タブを開きます。</li><li><strong>原材料追加</strong> を押します。</li><li>原材料名、単位、初期在庫数、原価、在庫少アラート閾値を入力します。</li><li>保存します。</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>内容</th><th>入力例</th></tr></thead><tbody><tr><td>原材料名</td><td>店舗で扱う食材や備品の名前</td><td>鶏肉、米、卵、ソース</td></tr><tr><td>単位</td><td>在庫を数える単位</td><td>g、kg、ml、L、個、枚</td></tr><tr><td>在庫数</td><td>現在の在庫量</td><td>5000</td></tr><tr><td>原価</td><td>単位あたりの原価</td><td>1gあたり2円、1個あたり40円</td></tr><tr><td>在庫少アラート閾値</td><td>この数値以下で注意表示・品切れ連動の対象</td><td>1000</td></tr></tbody></table><p>原材料一覧では、在庫数がアラート閾値以下になると目立つ表示になります。原材料を無効にした場合、その原材料は在庫連動の対象から外れます。</p><h2 id="原材料csv" tabindex="-1">原材料CSV <a class="header-anchor" href="#原材料csv" aria-label="Permalink to &quot;原材料CSV&quot;">​</a></h2><p>原材料一覧では、CSVエクスポートとCSVインポートができます。大量登録や棚卸し前の整理に使います。</p><table tabindex="0"><thead><tr><th>カラム</th><th>内容</th><th>必須</th></tr></thead><tbody><tr><td><code>id</code></td><td>既存原材料を更新する場合のID。空欄なら新規作成</td><td>任意</td></tr><tr><td><code>name</code></td><td>原材料名</td><td>必須</td></tr><tr><td><code>unit</code></td><td>単位。空欄の場合は「個」扱い</td><td>任意</td></tr><tr><td><code>stock_quantity</code></td><td>現在庫</td><td>任意</td></tr><tr><td><code>cost_price</code></td><td>単位あたり原価</td><td>任意</td></tr><tr><td><code>low_stock_threshold</code></td><td>低在庫アラート閾値</td><td>任意</td></tr><tr><td><code>sort_order</code></td><td>表示順</td><td>任意</td></tr><tr><td><code>is_active</code></td><td>有効/無効。通常は <code>1</code></td><td>任意</td></tr></tbody></table><p>CSVはUTF-8で保存してください。Excelで開いて文字化けする場合は、いったんCSVをエクスポートして、その列構成をサンプルとして編集すると安全です。</p><h2 id="レシピを設定する" tabindex="-1">レシピを設定する <a class="header-anchor" href="#レシピを設定する" aria-label="Permalink to &quot;レシピを設定する&quot;">​</a></h2><p>商品ごとに使用する原材料と数量を登録します。注文数に応じて在庫を確認しやすくなり、会計完了時の在庫減算、原価確認、品切れ連動の土台になります。</p><ol><li><strong>レシピ設定</strong> タブを開きます。</li><li>対象商品の <strong>レシピ編集</strong> を押します。</li><li>使用する原材料を選びます。</li><li>1食あたりの使用量を入力します。</li><li>必要な原材料を複数行追加します。</li></ol><p>例:</p><table tabindex="0"><thead><tr><th>商品</th><th>原材料</th><th style="text-align:right;">1食あたり使用量</th></tr></thead><tbody><tr><td>唐揚げ定食</td><td>鶏肉</td><td style="text-align:right;">180g</td></tr><tr><td>唐揚げ定食</td><td>米</td><td style="text-align:right;">200g</td></tr><tr><td>唐揚げ定食</td><td>タレ</td><td style="text-align:right;">30ml</td></tr></tbody></table><p>同じ商品に同じ原材料を重複登録することはできません。数量を変えたい場合は、既存行を編集します。</p><h2 id="レシピcsv" tabindex="-1">レシピCSV <a class="header-anchor" href="#レシピcsv" aria-label="Permalink to &quot;レシピCSV&quot;">​</a></h2><p>レシピ設定でもCSVエクスポートとCSVインポートができます。CSVでは商品名と原材料名で紐づけます。</p><table tabindex="0"><thead><tr><th>カラム</th><th>内容</th><th>必須</th></tr></thead><tbody><tr><td><code>recipe_id</code></td><td>既存レシピのID。エクスポート時に出力されます</td><td>任意</td></tr><tr><td><code>menu_name</code></td><td>メニュー名</td><td>必須</td></tr><tr><td><code>ingredient_name</code></td><td>原材料名</td><td>必須</td></tr><tr><td><code>ingredient_unit</code></td><td>原材料の単位。確認用</td><td>任意</td></tr><tr><td><code>quantity</code></td><td>1食あたり使用量</td><td>必須</td></tr></tbody></table><p>インポート時に、<code>menu_name</code> に一致するメニュー、<code>ingredient_name</code> に一致する原材料が見つからない行は取り込まれません。先にメニューと原材料を登録してからCSVを読み込んでください。</p><h2 id="品切れ連動" tabindex="-1">品切れ連動 <a class="header-anchor" href="#品切れ連動" aria-label="Permalink to &quot;品切れ連動&quot;">​</a></h2><p>レシピに紐づく原材料の在庫がアラート閾値以下になると、その原材料を使うメニューを店舗メニュー側で品切れ扱いにできます。</p><ul><li>会計完了後、在庫が減ったタイミングで品切れ同期が実行されます。</li><li>棚卸しで在庫が回復した場合は、在庫状態に応じて品切れ解除も行われます。</li><li>店舗メニューで手動の品切れ設定をしている場合は、在庫回復後に店舗側の表示も確認してください。</li></ul><div class="warning custom-block"><p class="custom-block-title">レシピ未設定の商品は自動判定されません</p><p>商品にレシピがない場合、POSLAはその商品がどの原材料を使っているか判断できません。売れ筋商品、限定商品、仕込み量が厳しい商品から優先してレシピを設定してください。</p></div><h2 id="棚卸し" tabindex="-1">棚卸し <a class="header-anchor" href="#棚卸し" aria-label="Permalink to &quot;棚卸し&quot;">​</a></h2><p>営業終了後や月末など、店舗の運用に合わせて棚卸しを行います。</p><ol><li><strong>原材料一覧</strong> を開きます。</li><li><strong>棚卸し開始</strong> を押します。</li><li>各原材料の実在庫を入力します。</li><li><strong>棚卸し保存</strong> を押します。</li><li>保存後、低在庫アラートや品切れ表示を確認します。</li></ol><p>実在庫とシステム上の在庫がずれている場合は、以下を確認してください。</p><ul><li>レシピの使用量が実際の仕込み量と合っているか</li><li>レシピ未設定の商品が売れていないか</li><li>廃棄、まかない、試作、ロスを手入力で調整していないか</li><li>返金や注文取消後の在庫戻しを棚卸しで補正したか</li><li>複数店舗で同じ原材料を扱う場合、店舗単位の運用ルールが決まっているか</li></ul><h2 id="ai需要予測" tabindex="-1">AI需要予測 <a class="header-anchor" href="#ai需要予測" aria-label="Permalink to &quot;AI需要予測&quot;">​</a></h2><p>過去の販売傾向、原材料在庫、レシピ設定をもとに、仕込みや発注の参考値を確認できます。AIアシスタントでは、在庫が少ない食材や、売れ筋メニューに必要な原材料を踏まえた相談ができます。</p><p>ただし、天候、周辺イベント、臨時休業、団体予約、仕入れ遅延など、システムに反映されない事情は店舗判断で調整してください。</p><h2 id="日次運用のおすすめ" tabindex="-1">日次運用のおすすめ <a class="header-anchor" href="#日次運用のおすすめ" aria-label="Permalink to &quot;日次運用のおすすめ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>タイミング</th><th>やること</th></tr></thead><tbody><tr><td>開店前</td><td>主要原材料の在庫数と品切れ表示を確認</td></tr><tr><td>ランチ後</td><td>売れ筋商品の原材料が夜営業分まで足りるか確認</td></tr><tr><td>夕方</td><td>限定メニューや品切れ候補を店舗メニューで確認</td></tr><tr><td>閉店後</td><td>棚卸し、廃棄・ロスの確認、翌日の仕込み判断</td></tr><tr><td>月末</td><td>原材料原価、レシピ設定、棚卸し差分を見直し</td></tr></tbody></table><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>在庫数が合わない</td><td>棚卸し、廃棄、仕入れ、手入力の履歴を確認してください。</td></tr><tr><td>品切れ表示が合わない</td><td>商品とレシピの紐づけ、低在庫の目安、店舗メニュー側の手動品切れ設定を確認してください。</td></tr><tr><td>需要予測が極端</td><td>休業日、イベント、異常値が含まれていないか確認してください。</td></tr><tr><td>CSVで文字化けする</td><td>UTF-8形式で保存してから取り込んでください。</td></tr><tr><td>レシピCSVが取り込まれない</td><td><code>menu_name</code> と <code>ingredient_name</code> が登録済みの名称と一致しているか確認してください。</td></tr><tr><td>会計しても在庫が減らない</td><td>レシピが設定されているか、商品がメニューテンプレートに紐づいているか確認してください。</td></tr></tbody></table>',48)])])}const u=d(l,[["render",i]]);export{p as __pageData,u as default};
